import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.next();

        // Create a buffer with fixed size of 10 characters
        char[] buffer = new char[10];

        // Copy user input into the buffer without checking length
        userInput.getChars(0, userInput.length(), buffer, 0);

        // Print out the contents of the buffer
        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

